#include <stdio.h>
int* countBits(int n, int* returnSize) {
    int* res = (int*)malloc((n + 1) * sizeof(int));
    *returnSize = n + 1;
    for (int i = 0; i <= n; i++) {
        int count = 0;
        int num = i;
        while (num) {
            count += num & 1;
            num >>= 1;
        }
        res[i] = count;
    }
    return res;
}

